function minSwaps(s) {
    let openBrackets = 0;
    let swaps = 0;

    for (let i = 0; i < s.length; i++) {
        const c = s[i];

        if (c === '[') {
            openBrackets++;
        } else {
            if (openBrackets === 0) {
                swaps++;
                openBrackets++;
            } else {
                openBrackets--;
            }
